#!/usr/bin/env python3
# .git/hooks/prepare-commit-msg
# Auto-appends Prompt-Hash: trailers for every staged prompt file.
# Install: chmod +x .git/hooks/prepare-commit-msg

import hashlib
import subprocess
import sys
from pathlib import Path

PROMPT_DIRS = ["prompts/", "agents/"]


def staged_files() -> list[str]:
    result = subprocess.run(
        ["git", "diff", "--cached", "--name-only", "--diff-filter=ACM"],
        capture_output=True, text=True, check=True,
    )
    return result.stdout.splitlines()


def is_prompt_file(path: str) -> bool:
    return any(path.startswith(d) for d in PROMPT_DIRS) and path.endswith(".txt")


def sha256_of_staged(path: str) -> str:
    # Hash the staged blob, not the working-tree file, so the hash
    # matches exactly what will be committed.
    result = subprocess.run(
        ["git", "show", f":{path}"],
        capture_output=True, check=True,
    )
    return hashlib.sha256(result.stdout).hexdigest()


def main():
    commit_msg_file = Path(sys.argv[1])
    prompt_files = [f for f in staged_files() if is_prompt_file(f)]
    if not prompt_files:
        return

    trailers = [
        f"Prompt-Hash: {p}:sha256:{sha256_of_staged(p)}"
        for p in sorted(prompt_files)
    ]

    existing = commit_msg_file.read_text()
    # Append trailers after a blank line separator if not already present
    separator = "\n" if existing.endswith("\n") else "\n\n"
    commit_msg_file.write_text(existing + separator + "\n".join(trailers) + "\n")


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""verify_prompt_hashes.py

For every commit in the current branch that carries Prompt-Hash: trailers,
re-compute the hash from the committed tree and compare. Reports mismatches.

Usage:
    python verify_prompt_hashes.py [--since <git-ref>]
"""
import hashlib
import re
import subprocess
import sys
from dataclasses import dataclass

TRAILER_RE = re.compile(
    r"^Prompt-Hash:\s+(?P<path>[^:]+):sha256:(?P<digest>[0-9a-f]{64})$",
    re.MULTILINE,
)


@dataclass
class Mismatch:
    commit: str
    path: str
    recorded: str
    actual: str


def commits_with_trailers(since: str = "HEAD~50") -> list[str]:
    result = subprocess.run(
        ["git", "log", "--format=%H", f"{since}..HEAD"],
        capture_output=True, text=True, check=True,
    )
    return result.stdout.splitlines()


def commit_body(sha: str) -> str:
    return subprocess.run(
        ["git", "log", "-1", "--format=%B", sha],
        capture_output=True, text=True, check=True,
    ).stdout


def blob_hash(sha: str, path: str) -> str:
    content = subprocess.run(
        ["git", "show", f"{sha}:{path}"],
        capture_output=True, check=True,
    ).stdout
    return hashlib.sha256(content).hexdigest()


def main(since: str = "HEAD~50") -> int:
    mismatches: list[Mismatch] = []
    for sha in commits_with_trailers(since):
        body = commit_body(sha)
        for m in TRAILER_RE.finditer(body):
            path, recorded = m.group("path"), m.group("digest")
            try:
                actual = blob_hash(sha, path)
            except subprocess.CalledProcessError:
                print(f"MISSING  {sha[:8]}  {path} (file not in tree)")
                continue
            if actual != recorded:
                mismatches.append(Mismatch(sha[:8], path, recorded, actual))

    if mismatches:
        for mm in mismatches:
            print(f"MISMATCH {mm.commit}  {mm.path}")
            print(f"  recorded: {mm.recorded}")
            print(f"  actual:   {mm.actual}")
        return 1
    print(f"OK — all Prompt-Hash trailers verified ({len(commits_with_trailers(since))} commits)")
    return 0


if __name__ == "__main__":
    since = sys.argv[2] if len(sys.argv) > 2 else "HEAD~50"
    sys.exit(main(since))

# cz_traceability.py — commitizen plugin for AI traceability fields
# Place in the repo root; configure: [tool.commitizen] name = "cz_traceability"

from commitizen.cz.base import BaseCommitizen
from commitizen.defaults import Questions


class TraceabilityCommitizen(BaseCommitizen):
    """Extends conventional commits with AI-system traceability questions."""

    bump_pattern = r"^(feat|fix|prompt|model)!"
    bump_map = {"feat!": "MAJOR", "fix!": "MINOR", "prompt": "PATCH", "model": "MINOR"}

    def questions(self) -> Questions:
        return [
            {
                "type": "list",
                "name": "type",
                "message": "Commit type",
                "choices": ["feat", "fix", "prompt", "eval", "model", "refactor", "docs", "ci"],
            },
            {
                "type": "input",
                "name": "scope",
                "message": "Agent name / scope (optional)",
            },
            {
                "type": "input",
                "name": "subject",
                "message": "Short description (50 chars)",
            },
            {
                "type": "input",
                "name": "safety_reviewer",
                "message": "Safety-Reviewer email (leave blank if not applicable)",
            },
            {
                "type": "input",
                "name": "model_version",
                "message": "Model-Version (leave blank if unchanged)",
            },
        ]

    def message(self, answers: dict) -> str:
        scope = f"({answers['scope']})" if answers.get("scope") else ""
        header = f"{answers['type']}{scope}: {answers['subject']}"
        trailers = []
        if answers.get("safety_reviewer"):
            trailers.append(f"Safety-Reviewer: {answers['safety_reviewer']}")
        if answers.get("model_version"):
            trailers.append(f"Model-Version: {answers['model_version']}")
        # Prompt-Hash and Eval-Run/Rate are added by hook + CI
        body = "\n".join(trailers)
        return f"{header}\n\n{body}" if body else header
